1	// Edge function: metrics-refresh (US-021)
2	//
3	// Contract:
4	//   POST { social_link_id: string }
5	//     → 200 {
6	//         status: 'queued' | 'already_fresh',
7	//         snapshot_ids: string[],     // ids of the latest fresh per-mode rows
8	//                                     //   on 'already_fresh' (1 for TikTok, 2
9	//                                     //   for Instagram); empty on 'queued'
10	//                                     //   until the pre-row model lands
11	//         metrics_status: { tiktok?: Status, ig_details?: Status, ig_posts?: Status },
12	//       }
13	//       where Status is 'fresh' | 'refreshing' | 'failed'.
14	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
15	//     → 401 { error: 'UNAUTHORIZED' }
16	//     → 403 { error: 'FORBIDDEN' }            // non-creator role
17	//     → 404 { error: 'LINK_NOT_FOUND' }       // social_link_id not owned by caller or missing
18	//     → 422 { error: 'LINK_UNLINKED' }        // the link is in status='unlinked'
19	//     → 429 { error: 'RATE_LIMIT', retry_after_sec: number }
20	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
21	//     → 502 { error: 'APIFY_ERROR' }          // every dispatched run rejected
22	//
23	// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Verifies via
24	//       _shared/jwt.ts and asserts role='creator'. Deployed with
25	//       verify_jwt=false at the gateway because the gateway only knows
26	//       about Supabase's own JWT secret — the handler enforces auth.
27	//
28	// Throttle: per spec §5.2 / §1.6 a creator may refresh at most once
29	// per 6h per social_link. Keyed on `social_links.last_scrape_attempt_at`
30	// and enforced with a SINGLE conditional UPDATE (atomic CAS):
31	//
32	//   UPDATE social_links
33	//     SET last_scrape_attempt_at = now()
34	//   WHERE id = $1
35	//     AND (last_scrape_attempt_at IS NULL
36	//          OR last_scrape_attempt_at < now() - interval '6 hours')
37	//   RETURNING last_scrape_attempt_at
38	//
39	// If zero rows come back the throttle is still active → 429. This closes
40	// the TOCTOU window a SELECT-then-UPDATE pair would leave: two concurrent
41	// refreshes for the same link can't both pass the gate. The bump happens
42	// BEFORE Apify dispatch so a downstream failure still burns the 6h window
43	// — this intentionally costs the creator a 6h retry if dispatch flakes,
44	// but protects Apify budget against spam through a flaky path.
45	//
46	// already_fresh: §5.2 returns `status: 'already_fresh'` when the creator
47	// already has fresh-enough data for every scrape_mode the platform
48	// requires (tiktok_profile for TikTok; ig_details + ig_posts for
49	// Instagram). The check runs BEFORE the throttle bump: if
50	// metric_snapshots has an `is_latest=true`, `status='fresh'` row per
51	// required mode whose `fetched_at` is within the throttle window (6h),
52	// we return the ids of those rows with `status='already_fresh'` and
53	// skip Apify entirely. This path is reachable today because the webhook
54	// RPCs (US-016..US-018) do set `status='fresh'` + `is_latest=true` on
55	// success.
56	//
57	// Dispatch: mirrors US-020 (auth-signup-creator). TikTok triggers 1
58	// run (tiktok_profile); Instagram triggers 2 runs (ig_details +
59	// ig_posts). Each run registers a per-run webhook pointing at
60	// /functions/v1/apify-webhook. waitSecs=60 matches the signup path so
61	// the UI can either render 'fresh' immediately or 'refreshing' and
62	// poll. Promise.allSettled — partial failure reports a 'failed' status
63	// for that mode; the creator keeps whatever they already had. If
64	// EVERY task rejected at the network layer the endpoint returns
65	// 502 APIFY_ERROR so the client can distinguish "apify is down" from
66	// "scrape will finish asynchronously".
67	//
68	// Spec gap: §5.2 specifies `snapshot_ids` on the `queued` response as
69	// pre-inserted `status='refreshing'` rows. US-016..US-020 ship with
70	// INSERT + ON CONFLICT DO NOTHING in the webhook RPCs (no UPDATE-or-
71	// INSERT), so pre-rows would leave permanent `refreshing` rows the
72	// webhook can't clear. Once a webhook RPC story extends each persist_*
73	// RPC to UPDATE-or-INSERT, this function can pre-insert the rows and
74	// return real ids on `queued`. Until then snapshot_ids is [] on
75	// `queued` and the UI must rely on realtime subscriptions to
76	// metric_snapshots keyed on social_link_id (per US-036).
77	// metrics_status keeps the client informed of the per-mode outcome —
78	// mirrors the US-020 shape so clients can share rendering code.
79	//
80	// Cost/rate: APIFY_KEY + APIFY_WEBHOOK_SECRET must be set. If absent,
81	// returns 500 SERVER_MISCONFIGURED before bumping `last_scrape_attempt_at`
82	// so the throttle is not burned when dispatch isn't possible.
83	
84	import { createClient } from "npm:@supabase/supabase-js@2";
85	import { verifyJwt } from "../_shared/jwt.ts";
86	import { corsHeaders } from "../_shared/cors.ts";
87	import {
88	  type ApifyRunResult,
89	  type ApifyWebhookSpec,
90	  runInstagramDetails,
91	  runInstagramPosts,
92	  runTikTokProfile,
93	} from "../_shared/apify.ts";
94	
95	const THROTTLE_SECS = 6 * 60 * 60;
96	const APIFY_WAIT_SECS = 60;
97	const APIFY_TERMINAL_EVENTS = [
98	  "ACTOR.RUN.SUCCEEDED",
99	  "ACTOR.RUN.FAILED",
100	  "ACTOR.RUN.TIMED_OUT",
101	  "ACTOR.RUN.ABORTED",
102	];
103	const UUID_RE =
104	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
105	
106	type MetricsKey = "tiktok" | "ig_details" | "ig_posts";
107	type MetricsStatus = "fresh" | "refreshing" | "failed";
108	
109	interface RefreshRequest {
110	  social_link_id?: unknown;
111	}
112	
113	interface SocialLinkRow {
114	  id: string;
115	  user_id: string;
116	  platform: "tiktok" | "instagram";
117	  handle: string;
118	  status: string;
119	  last_scrape_attempt_at: string | null;
120	}
121	
122	function jsonResponse(status: number, body: unknown): Response {
123	  return new Response(JSON.stringify(body), {
124	    status,
125	    headers: { ...corsHeaders, "Content-Type": "application/json" },
126	  });
127	}
128	
129	function bearerToken(req: Request): string | null {
130	  const raw = req.headers.get("Authorization") ?? req.headers.get("authorization");
131	  if (!raw) return null;
132	  const m = raw.match(/^Bearer\s+(.+)$/i);
133	  return m ? m[1].trim() : null;
134	}
135	
136	Deno.serve(async (req) => {
137	  if (req.method === "OPTIONS") {
138	    return new Response(null, { status: 204, headers: corsHeaders });
139	  }
140	  if (req.method !== "POST") {
141	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
142	  }
143	
144	  const token = bearerToken(req);
145	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
146	
147	  let claims;
148	  try {
149	    claims = await verifyJwt(token);
150	  } catch {
151	    return jsonResponse(401, { error: "UNAUTHORIZED" });
152	  }
153	  if (claims.role !== "creator") {
154	    return jsonResponse(403, { error: "FORBIDDEN" });
155	  }
156	
157	  let body: RefreshRequest;
158	  try {
159	    body = await req.json();
160	  } catch {
161	    return jsonResponse(400, { error: "INVALID_JSON" });
162	  }
163	
164	  const socialLinkId =
165	    typeof body.social_link_id === "string" &&
166	    UUID_RE.test(body.social_link_id)
167	      ? body.social_link_id
168	      : null;
169	  if (!socialLinkId) {
170	    return jsonResponse(400, { error: "INVALID_REQUEST" });
171	  }
172	
173	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
174	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
175	  const apifyKey = Deno.env.get("APIFY_KEY");
176	  const webhookSecret = Deno.env.get("APIFY_WEBHOOK_SECRET");
177	  if (!supabaseUrl || !serviceRoleKey || !apifyKey || !webhookSecret) {
178	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
179	  }
180	
181	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
182	    auth: { persistSession: false, autoRefreshToken: false },
183	  });
184	
185	  const { data: link, error: linkError } = await supabase
186	    .from("social_links")
187	    .select(
188	      "id,user_id,platform,handle,status,last_scrape_attempt_at",
189	    )
190	    .eq("id", socialLinkId)
191	    .maybeSingle();
192	
193	  if (linkError) {
194	    console.error("social_links lookup failed", linkError);
195	    return jsonResponse(500, { error: "DB_ERROR" });
196	  }
197	  const row = link as SocialLinkRow | null;
198	  if (!row || row.user_id !== claims.sub) {
199	    // 404 rather than 403 so the endpoint doesn't leak which ids exist
200	    // for other creators.
201	    return jsonResponse(404, { error: "LINK_NOT_FOUND" });
202	  }
203	  if (row.status === "unlinked") {
204	    return jsonResponse(422, { error: "LINK_UNLINKED" });
205	  }
206	
207	  const requiredModes = requiredScrapeModes(row.platform);
208	  const nowMs = Date.now();
209	  const cutoffIso = new Date(nowMs - THROTTLE_SECS * 1000).toISOString();
210	
211	  // already_fresh short-circuit: the creator already has current data for
212	  // every required mode, so we skip Apify and return the existing ids.
213	  // Runs BEFORE the throttle bump so a caller who polls repeatedly while
214	  // data is fresh doesn't burn their 6h window.
215	  const freshSnapshots = await fetchLatestFreshSnapshots(
216	    supabase,
217	    row.id,
218	    requiredModes,
219	    cutoffIso,
220	  );
221	  if (freshSnapshots === "db_error") {
222	    return jsonResponse(500, { error: "DB_ERROR" });
223	  }
224	  if (freshSnapshots.size === requiredModes.length) {
225	    const alreadyFreshMetrics: Partial<Record<MetricsKey, MetricsStatus>> = {};
226	    for (const mode of requiredModes) {
227	      alreadyFreshMetrics[modeToMetricsKey(mode)] = "fresh";
228	    }
229	    return jsonResponse(200, {
230	      status: "already_fresh",
231	      snapshot_ids: requiredModes.map((m) => freshSnapshots.get(m)!),
232	      metrics_status: alreadyFreshMetrics,
233	    });
234	  }
235	
236	  // Atomic 6h throttle check + bump in a single conditional UPDATE. If
237	  // zero rows come back the throttle was already active when we raced
238	  // another request; we then re-read `last_scrape_attempt_at` to compute
239	  // retry_after_sec. Concurrent callers can't both pass this gate.
240	  const nowIso = new Date(nowMs).toISOString();
241	  const { data: bumped, error: bumpError } = await supabase
242	    .from("social_links")
243	    .update({ last_scrape_attempt_at: nowIso })
244	    .eq("id", row.id)
245	    .or(`last_scrape_attempt_at.is.null,last_scrape_attempt_at.lt.${cutoffIso}`)
246	    .select("id");
247	  if (bumpError) {
248	    console.error("social_links last_scrape_attempt_at bump failed", bumpError);
249	    return jsonResponse(500, { error: "DB_ERROR" });
250	  }
251	  if (!bumped || bumped.length === 0) {
252	    const retryAfterSec = await computeRetryAfterSec(
253	      supabase,
254	      row.id,
255	      nowMs,
256	    );
257	    return jsonResponse(429, {
258	      error: "RATE_LIMIT",
259	      retry_after_sec: retryAfterSec,
260	    });
261	  }
262	
263	  const { metricsStatus, allFailed } = await dispatchApifyRuns({
264	    supabaseUrl,
265	    webhookSecret,
266	    link: row,
267	  });
268	
269	  if (allFailed) {
270	    return jsonResponse(502, { error: "APIFY_ERROR" });
271	  }
272	
273	  return jsonResponse(200, {
274	    status: "queued",
275	    snapshot_ids: [] as string[],
276	    metrics_status: metricsStatus,
277	  });
278	});
279	
280	function requiredScrapeModes(
281	  platform: SocialLinkRow["platform"],
282	): Array<"tiktok_profile" | "ig_details" | "ig_posts"> {
283	  return platform === "tiktok"
284	    ? ["tiktok_profile"]
285	    : ["ig_details", "ig_posts"];
286	}
287	
288	function modeToMetricsKey(
289	  mode: "tiktok_profile" | "ig_details" | "ig_posts",
290	): MetricsKey {
291	  return mode === "tiktok_profile" ? "tiktok" : mode;
292	}
293	
294	// Returns a Map<scrape_mode, snapshot_id> containing the latest fresh
295	// snapshot per required mode whose fetched_at is newer than the cutoff.
296	// The Map is empty-or-partial if any required mode lacks a fresh row.
297	// deno-lint-ignore no-explicit-any -- supabase-js generic args differ
298	// between the createClient call above (inferred as public schema) and
299	// any helper import; typing loosely avoids a widening mismatch.
300	async function fetchLatestFreshSnapshots(
301	  supabase: any,
302	  socialLinkId: string,
303	  requiredModes: Array<"tiktok_profile" | "ig_details" | "ig_posts">,
304	  cutoffIso: string,
305	): Promise<Map<string, string> | "db_error"> {
306	  const { data, error } = await supabase
307	    .from("metric_snapshots")
308	    .select("id,scrape_mode,fetched_at")
309	    .eq("social_link_id", socialLinkId)
310	    .eq("is_latest", true)
311	    .eq("status", "fresh")
312	    .in("scrape_mode", requiredModes)
313	    .gte("fetched_at", cutoffIso);
314	  if (error) {
315	    console.error("metric_snapshots lookup failed", error);
316	    return "db_error";
317	  }
318	  const rows = (data ?? []) as Array<{ id: string; scrape_mode: string }>;
319	  const out = new Map<string, string>();
320	  for (const r of rows) {
321	    if (requiredModes.includes(r.scrape_mode as (typeof requiredModes)[number])) {
322	      out.set(r.scrape_mode, r.id);
323	    }
324	  }
325	  return out;
326	}
327	
328	// Re-reads last_scrape_attempt_at after the CAS UPDATE returned zero rows
329	// so the 429 carries an accurate retry_after_sec. If the read fails for
330	// any reason we fall back to the full throttle window rather than leak a
331	// DB_ERROR on a path that's already a rejection.
332	// deno-lint-ignore no-explicit-any -- see note above on supabase-js generics
333	async function computeRetryAfterSec(
334	  supabase: any,
335	  socialLinkId: string,
336	  nowMs: number,
337	): Promise<number> {
338	  const { data, error } = await supabase
339	    .from("social_links")
340	    .select("last_scrape_attempt_at")
341	    .eq("id", socialLinkId)
342	    .maybeSingle();
343	  if (error || !data?.last_scrape_attempt_at) {
344	    return THROTTLE_SECS;
345	  }
346	  const lastMs = Date.parse(data.last_scrape_attempt_at);
347	  if (!Number.isFinite(lastMs)) return THROTTLE_SECS;
348	  const elapsedSec = Math.floor((nowMs - lastMs) / 1000);
349	  return Math.max(1, THROTTLE_SECS - elapsedSec);
350	}
351	
352	async function dispatchApifyRuns(params: {
353	  supabaseUrl: string;
354	  webhookSecret: string;
355	  link: SocialLinkRow;
356	}): Promise<{
357	  metricsStatus: Partial<Record<MetricsKey, MetricsStatus>>;
358	  allFailed: boolean;
359	}> {
360	  const { supabaseUrl, webhookSecret, link } = params;
361	  const metricsStatus: Partial<Record<MetricsKey, MetricsStatus>> = {};
362	
363	  const webhookUrl = `${supabaseUrl}/functions/v1/apify-webhook`;
364	  const buildWebhook = (
365	    linkId: string,
366	    scrapeMode: "tiktok_profile" | "ig_details" | "ig_posts",
367	  ): ApifyWebhookSpec => ({
368	    eventTypes: APIFY_TERMINAL_EVENTS,
369	    requestUrl: webhookUrl,
370	    payloadTemplate: JSON.stringify({
371	      eventType: "{{eventType}}",
372	      resource: {
373	        id: "{{resource.id}}",
374	        defaultDatasetId: "{{resource.defaultDatasetId}}",
375	        status: "{{resource.status}}",
376	        actId: "{{resource.actId}}",
377	      },
378	      social_link_id: linkId,
379	      scrape_mode: scrapeMode,
380	      run_id: "{{resource.id}}",
381	      dataset_id: "{{resource.defaultDatasetId}}",
382	    }),
383	    headersTemplate: JSON.stringify({
384	      "X-Apify-Webhook-Secret": webhookSecret,
385	    }),
386	    shouldInterpolateStrings: true,
387	  });
388	
389	  interface Task {
390	    key: MetricsKey;
391	    run: () => Promise<ApifyRunResult>;
392	  }
393	  const tasks: Task[] = [];
394	  if (link.platform === "tiktok") {
395	    tasks.push({
396	      key: "tiktok",
397	      run: () =>
398	        runTikTokProfile(link.handle, {
399	          waitSecs: APIFY_WAIT_SECS,
400	          webhooks: [buildWebhook(link.id, "tiktok_profile")],
401	        }),
402	    });
403	  } else if (link.platform === "instagram") {
404	    tasks.push({
405	      key: "ig_details",
406	      run: () =>
407	        runInstagramDetails(link.handle, {
408	          waitSecs: APIFY_WAIT_SECS,
409	          webhooks: [buildWebhook(link.id, "ig_details")],
410	        }),
411	    });
412	    tasks.push({
413	      key: "ig_posts",
414	      run: () =>
415	        runInstagramPosts(link.handle, {
